import React from 'react';

import { Props } from './Image.types';

export const Image: React.FC<Props> = props => {
  const { pixelRatio, ...imageProps } = props;

  if (pixelRatio) {
    // Split string by last DOT “.”
    const [path, ext] = imageProps.src.split(/\.(?=[^.]+$)/);

    // Add srcset image attribute to all image props
    imageProps.srcSet = '';
    for (let i = 1; i <= pixelRatio; i++) {
      if (i === 1) {
        imageProps.srcSet += `${path}.${ext} 1x`;
      } else {
        imageProps.srcSet += `, ${path}@${i}x.${ext} ${i}x`;
      }
    }
  }

  return <img alt="" {...imageProps} />;
};
